    subject_triples: dict[str, list[Triple]] = {}
    for t in triples:
        if t.subject not in subject_triples:
            subject_triples[t.subject] = []
        subject_triples[t.subject].append(t)

    # Identify the main subject (usually the celestial body)
    main_subject = None
    discoverer_subjects = set()

    for t in triples:
        if t.predicate.lower() == "discoverer":
            discoverer_subjects.add(t.object)

    # Find main subject (not a discoverer)
    for subj in subject_triples.keys():
        if subj not in discoverer_subjects:
            main_subject = subj
            break

    if main_subject is None:
        main_subject = list(subject_triples.keys())[0] if subject_triples else None

    # Keep object value with units for better readability
    def clean_obj(obj: str) -> str:
        """
        Strip whitespace, remove surrounding quotes and format numbers with units.
        Example: "7715100000.0 (kilometres)" → "7,715,100,000 kilometres"
        """
        obj = obj.strip()
        # Remove surrounding quotes if present
        if obj.startswith('"') and obj.endswith('"'):
            obj = obj[1:-1]
        # Match a number optionally followed by a unit in parentheses
        m = re.match(r'^([\d\.]+)\s*\(?\s*([^\)]+)\s*\)?$', obj)
        if m:
            number, unit = m.groups()
            try:
                num_val = float(number)
                if num_val.is_integer():
                    number_fmt = f"{int(num_val):,}"
                else:
                    number_fmt = f"{num_val:,}"
            except ValueError:
                number_fmt = number
            return f"{number_fmt} {unit}"
        return obj

