        if p == "minimumtemperature":
            return f"{subj_word} has a minimum temperature of {clean_obj_val}" if not combine_with_prev else f"with a minimum temperature of {clean_obj_val}"
        if p == "rotationperiod":
            return f"{subj_word} has a rotation period of {clean_obj_val}" if not combine_with_prev else f"with a rotation period of {clean_obj_val}"
        if p == "surfacearea":
            return f"{subj_word} has a surface area of {clean_obj_val}" if not combine_with_prev else f"with a surface area of {clean_obj_val}"
        if p == "absolutemagnitude":
            return f"{subj_word} has an absolute magnitude of {clean_obj_val}" if not combine_with_prev else f"with an absolute magnitude of {clean_obj_val}"
        if p == "formername":
            return f"{subj_word} was formerly known as {clean_obj_val}"
        if p == "birthdate":
            return f"{subj_word} was born on {clean_obj_val}"
        if p == "deathdate":
            return f"{subj_word} died on {clean_obj_val}"
        if p == "birthplace":
            return f"{subj_word} was born in {clean_obj_val}"
        if p == "deathplace":
            return f"{subj_word} died in {clean_obj_val}"
        if p == "deathcause":
            return f"{subj_word} died of {clean_obj_val}"
        if p in ("nationality", "stateoforigin"):
            return f"{subj_word} is from {clean_obj_val}"
        if p == "almamater":
            return f"{subj_word} studied at {clean_obj_val}"
        if p == "doctoralstudent":
